import React, { useState } from 'react';
import axios from 'axios';

function NoteForm({ fetchNotes }) {
  const [form, setForm] = useState({ title: '', content: '' });
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!form.title || !form.content) return alert("Fill all fields");
    setIsSubmitting(true);
    try {
      await axios.post('http://localhost:5001/api/notes', form);
      fetchNotes();
      setForm({ title: '', content: '' });
    } catch (err) { console.error(err); } finally { setIsSubmitting(false); }
  };

  const formCardStyle = {
    background: '#fff',
    padding: '32px',
    borderRadius: '20px',
    boxShadow: '0 10px 15px -3px rgba(0, 0, 0, 0.1)',
    maxWidth: '600px',
    margin: '0 auto 50px auto',
    border: '1px solid #e2e8f0'
  };

  const inputStyle = {
    width: '100%',
    padding: '12px 16px',
    borderRadius: '10px',
    border: '1px solid #cbd5e1',
    marginTop: '8px',
    marginBottom: '20px',
    fontSize: '1rem',
    boxSizing: 'border-box'
  };

  const buttonStyle = {
    width: '100%',
    padding: '14px',
    backgroundColor: '#4f46e5',
    color: 'white',
    border: 'none',
    borderRadius: '10px',
    fontWeight: '600',
    cursor: 'pointer',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    gap: '10px',
    transition: '0.2s'
  };

  return (
    <div style={formCardStyle}>
      <h2 style={{ margin: '0 0 24px 0', fontSize: '1.25rem' }}>Create New Note</h2>
      <form onSubmit={handleSubmit}>
        <label style={{ fontSize: '0.85rem', fontWeight: '600', color: '#64748b' }}>Title</label>
        <input
          style={inputStyle}
          placeholder="e.g., Kubernetes Pod Lifecycle"
          value={form.title}
          onChange={e => setForm({ ...form, title: e.target.value })}
        />

        <label style={{ fontSize: '0.85rem', fontWeight: '600', color: '#64748b' }}>Content</label>
        <textarea
          style={{ ...inputStyle, height: '100px', resize: 'none' }}
          placeholder="Write your technical thoughts..."
          value={form.content}
          onChange={e => setForm({ ...form, content: e.target.value })}
        />

        <button 
          type="submit" 
          disabled={isSubmitting} 
          style={buttonStyle}
          onMouseOver={(e) => e.target.style.backgroundColor = '#4338ca'}
          onMouseOut={(e) => e.target.style.backgroundColor = '#4f46e5'}
        >
          {isSubmitting ? "Saving..." : "Add to Vault"}
          <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><line x1="12" y1="5" x2="12" y2="19"></line><line x1="5" y1="12" x2="19" y2="12"></line></svg>
        </button>
      </form>
    </div>
  );
}

export default NoteForm;
